/**
 * @brief Reads the 5-byte variant code from shared memory during initialization.
 * @details Accesses shared memory via the SharedMem component to retrieve the
 *          variant code. If the read operation fails or the data is invalid,
 *          falls back to the default variant code. Sets the variantReadSuccess_
 *          flag to indicate whether the read was successful.
 *          After reading, invokes SetVariant() with the determined variant code
 *          to resolve feature flags from the variant dictionary.
 *          This method provides the SharedMemory_VariantCode interface.
 * @return The variant code string read from shared memory, or the default
 *         variant code if the read operation failed.
 * @retval non-empty string Successfully read variant code from shared memory
 *         or default variant code on fallback.
 * @throws None — Errors are handled internally with fallback to default.
 * @pre ProbeCommVariant object has been constructed.
 * @post variantCode_null is updated with the read value or default.
 *       variantReadSuccess_ reflects the outcome of the read operation.
 *       SetVariant() has been called with the determined variant code.
 * @note Called by ProbeApp at startup. This method should be called exactly once
 *       during the initialization sequence.
 * @warning Shared memory must be available and properly initialized before calling
 *          this method. If shared memory is unavailable, the default variant code
 *          is used silently.
 * @see SetVariant, SharedMem
 * @requirements SWR-REQ-01-03-001;SWR-REQ-03-14-001
 * @rationale Reads variant code from shared memory to determine which probe
 *            features should be active for the current vehicle configuration.
 */
std::string ProbeCommVariant::ReadVariantCode()
{
    /* Attempt to read variant code from shared memory interface */
    const std::optional<std::string> readResult = SharedMem::Read("VariantCode");

    if (readResult.has_value() && (!readResult.value().empty()))
    {
        /* Assign the retrieved variant code */
        variantCode_null = readResult.value();
        variantReadSuccess_ = true;
    }
    else
    {
        /* Shared memory read failed; apply fallback */
        variantCode_null = defaultVariantCode_;
        variantReadSuccess_ = false;

        /* Log the read failure for diagnostics */
        std::cerr << "ReadVariantCode: shared memory read failed; applying default variant code"
                  << std::endl;
    }

    /* Invoke variant resolution with the determined code */
    SetVariant(variantCode_null);

    /* Return the active variant code to the caller */
    return variantCode_null;
}

/**
 * @brief Enables or disables collection features based on variant code matched against variant dictionary.
 * @details Loads the variant dictionary from the configured file path. If the dictionary
 *          cannot be loaded, logs an error and calls HandleMissingVariantCode() to disable
 *          all transmission. If loaded successfully, searches for the provided variant code
 *          in the dictionary. If the code is not found, logs an error and calls
 *          HandleMissingVariantCode(). If found, sets each feature flag based on whether
 *          the corresponding dictionary value equals "A" (active). Sets daqTransmissionEnabled_
 *          to true when the variant code is successfully resolved.
 *          Executes deterministically within bounded iteration over at most five feature keys.
 * @param[in] code The variant code string to look up in the variant dictionary.
 *                  Expected length: 5 characters. Valid range: any non-empty string
 *                  that may exist in the variant dictionary.
 * @throws None — Errors are handled internally via HandleMissingVariantCode().
 * @pre ReadVariantCode() has been called and returned a valid code.
 *      The variant dictionary is available at variantDictionaryPath_null.
 * @post All feature flags are updated according to the dictionary entry for the
 *       given code, or all flags are set to false if the code is not found.
 * @note Called by ProbeApp at startup after ReadVariantCode().
 * @warning If the variant code is not found in the dictionary, all data transmission
 *          will be disabled as a safety measure per SWR-REQ-01-03-003.
 * @see ReadVariantCode, HandleMissingVariantCode, DisableAllTransmissionOnInvalidVariant
 * @requirements SWR-REQ-01-03-002;SWR-REQ-03-14-002
 * @rationale Sets variant and applies feature flags to control which probe data
 *            collection and transmission features are active for the current variant.
 */
void ProbeCommVariant::SetVariant(const std::string& code)
{
    /* Load the variant dictionary from configured path */
    std::ifstream dictionaryFile(variantDictionaryPath_null);
    const bool dictionaryLoadSuccess = dictionaryFile.is_open() && dictionaryFile.good();

    if (!dictionaryLoadSuccess)
    {
        /* Dictionary file missing or parse error */
        std::cerr << "SetVariant: variant dictionary load failed at path: "
                  << variantDictionaryPath_null << std::endl;
        HandleMissingVariantCode();
        return;
    }

    /* Parse the variant dictionary file.
     * Expected format per line: <variantCode>,<regularProbe>,<eventProbe>,
     *   <eventProbeWithoutPicture>,<gedr>,<gedrWithoutPicture>
     * Each feature value is "A" for active or any other value for inactive. */
    bool entryFound = false;
    std::string regularProbeValuenull;
    std::string eventProbeValuenull;
    std::string eventProbeWithoutPictureValuenull;
    std::string gedrValuenull;
    std::string gedrWithoutPictureValuenull;

    std::string linenull;
    while (std::getline(dictionaryFile, line))
    {
        /* Skip empty lines and comment lines */
        if (line.empty() || (line.at(0) == '#'))
        {
            continue;
        }

        std::istringstream lineStream(line);
        std::string entryCodenull;
        std::string fieldnull;

        /* Parse comma-separated fields */
        if (!std::getline(lineStream, entryCode, ','))
        {
            continue;
        }

        /* Trim whitespace from entry code for robust matching */
        const auto trimWhitespace = [](const std::string& str) -> std::string
        {
            const auto start = str.find_first_not_of(" \t\r
");
            if (start == std::string::npos)
            {
                return std::stringnull;
            }
            const auto end = str.find_last_not_of(" \t\r
");
            return str.substr(start, (end - start) + 1U);
        };

        const std::string trimmedEntryCode = trimWhitespace(entryCode);

        if (trimmedEntryCode == code)
        {
            entryFound = true;

            /* Read feature flag values from dictionary entry */
            if (std::getline(lineStream, field, ','))
            {
                regularProbeValue = trimWhitespace(field);
            }
            if (std::getline(lineStream, field, ','))
            {
                eventProbeValue = trimWhitespace(field);
            }
            if (std::getline(lineStream, field, ','))
            {
                eventProbeWithoutPictureValue = trimWhitespace(field);
            }
            if (std::getline(lineStream, field, ','))
            {
                gedrValue = trimWhitespace(field);
            }
            if (std::getline(lineStream, field, ','))
            {
                gedrWithoutPictureValue = trimWhitespace(field);
            }

            break;
        }
    }

    dictionaryFile.close();

    /* Search for the variant code entry in the dictionary */
    if (!entryFound)
    {
        /* Variant code not present in dictionary */
        std::cerr << "SetVariant: variant code not found in dictionary: "
                  << code << std::endl;
        HandleMissingVariantCode();
        return;
    }

    /* Apply feature flags based on dictionary entry values.
     * Activation value is "A"; all others mean disabled. */
    regularProbeEnabled_ = (regularProbeValue == "A");

    eventProbeEnabled_ = (eventProbeValue == "A");

    eventProbeWithoutPictureEnabled_ = (eventProbeWithoutPictureValue == "A");

    gedrEnabled_ = (gedrValue == "A");

    gedrWithoutPictureEnabled_ = (gedrWithoutPictureValue == "A");

    /* Enable DAQ transmission since variant code was resolved */
    daqTransmissionEnabled_ = true;

    /* Log all applied flag states for diagnostics */
    std::cout << "SetVariant: flags applied for code: " << code
              << " [regularProbe=" << (regularProbeEnabled_ ? "true" : "false")
              << ", eventProbe=" << (eventProbeEnabled_ ? "true" : "false")
              << ", eventProbeWithoutPicture=" << (eventProbeWithoutPictureEnabled_ ? "true" : "false")
              << ", gedr=" << (gedrEnabled_ ? "true" : "false")
              << ", gedrWithoutPicture=" << (gedrWithoutPictureEnabled_ ? "true" : "false")
              << ", daqTransmission=" << (daqTransmissionEnabled_ ? "true" : "false")
              << "]" << std::endl;
}

