/**
 * @brief Logs error and prevents data transmission when variant code not found in dictionary.
 * @details Called internally by SetVariant() when the provided variant code does not
 *          match any entry in the variant dictionary. Logs an error message to std::cerr
 *          containing the current variantCode_ and variantReadSuccess_ state for diagnostic
 *          context, then invokes DisableAllTransmissionOnInvalidVariant() to set all feature
 *          flags to false. After this call, no data collection or transmission to DAQ or
 *          GEDR is possible until a system restart provides a valid variant. Execution is
 *          deterministic and bounded in O(1).
 *          Thread-safety: Safe to call from a single thread context as designed.
 * @throws None — Errors are handled internally.
 * @pre SetVariant() has been called with a code not present in the variant dictionary.
 * @post All feature flags are set to false. An error message has been logged to std::cerr.
 * @note Called by: ProbeCommVariant (SetVariant) during startup when variant code is missing.
 * @warning This method disables ALL transmission features. Recovery requires a system
 *          restart with a valid variant code. No automatic recovery is provided.
 * @see SetVariant, DisableAllTransmissionOnInvalidVariant
 * @requirements SWR-REQ-01-03-003;SWR-REQ-03-14-003
 * @rationale Handles missing variant code as a safety measure to prevent data
 *            transmission with an unrecognized vehicle configuration, compliant
 *            with ISO 26262 ASIL-B requirements.
 */
void ProbeCommVariant::HandleMissingVariantCode()
{
    /* Log the error with variant code context */
    std::cerr << "HandleMissingVariantCode: variant code not resolved: "
              << variantCode_
              << " readSuccess: "
              << (variantReadSuccess_ ? "true" : "false")
              << std::endl;

    /* Disable all data transmission to DAQ and GEDR */
    DisableAllTransmissionOnInvalidVariant();

    /* No further processing; function returns */
}

/**
 * @brief Disables all data sending to DAQ and GEDR when variant is invalid.
 * @details Unconditionally sets all six feature enablement flags (regularProbeEnabled_,
 *          eventProbeEnabled_, eventProbeWithoutPictureEnabled_, gedrEnabled_,
 *          gedrWithoutPictureEnabled_, daqTransmissionEnabled_) to false in a sequential
 *          manner. There are no conditions or branches. No external service is accessed.
 *          After this function returns, all check functions (CheckRegularProbeEnabled,
 *          CheckEventProbeEnabled, CheckEventProbeWithoutPictureEnabled, CheckGedrEnabled,
 *          CheckGedrWithoutPictureEnabled, CheckDaqTransmissionEnabled) will return false,
 *          preventing any data flow. Logs the disablement for diagnostic traceability.
 *          Execution is deterministic and bounded in O(1).
 *          Thread-safety: Safe to call from a single thread context as designed.
 * @throws None — This function is noexcept.
 * @pre Called from HandleMissingVariantCode() or SetVariant() when variant is invalid.
 * @post All six feature flags are set to false. A diagnostic log message has been output.
 * @note Called by: ProbeCommVariant internally during startup error handling.
 * @warning After this call, no probe data collection or transmission will occur
 *          until SetVariant() is called again with a valid variant code.
 * @see HandleMissingVariantCode, SetVariant
 * @requirements SWR-REQ-01-03-003;SWR-REQ-03-14-003
 * @rationale Disables all transmission on invalid variant as a safety measure
 *            compliant with ISO 26262 ASIL-B requirements, ensuring no data is
 *            transmitted for an unrecognized vehicle configuration.
 */
void ProbeCommVariant::DisableAllTransmissionOnInvalidVariant() noexcept
{
    /* Unconditionally disable all collection and transmission flags */
    regularProbeEnabled_ = false;
    eventProbeEnabled_ = false;
    eventProbeWithoutPictureEnabled_ = false;
    gedrEnabled_ = false;
    gedrWithoutPictureEnabled_ = false;
    daqTransmissionEnabled_ = false;

    /* Log the disablement for diagnostic traceability */
    std::cout << "DisableAllTransmissionOnInvalidVariant: all transmission flags disabled"
              << std::endl;
}

